import React, { useState, useEffect } from "react";
import "../styles.css";
import TarjetaReserva from "./TarjetaReserva";

export default function SeccionCarros({ onSelectVehicle }) {
  const [vehiculos, setVehiculos] = useState([]);
  const [filtro, setFiltro] = useState("todos");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedVehicle, setSelectedVehicle] = useState(null);

  useEffect(() => {
    async function fetchVehiculos() {
      try {
        const res = await fetch("/api/vehiculos");
        if (!res.ok) throw new Error("Error al cargar vehículos");
        const data = await res.json();
        setVehiculos(data);
        setLoading(false);
      } catch (err) {
        setError(err.message);
        setLoading(false);
      }
    }
    fetchVehiculos();
  }, []);

  const handleSelect = (vehicle) => {
    onSelectVehicle({
      ID_Vehiculo: vehicle.ID_Vehiculo,
      Marca: vehicle.Marca,
      Modelo: vehicle.Modelo,
      Tipo: vehicle.Tipo,
      Precio: vehicle.Precio,
    });
  };

  const filtrarVehiculos = () => {
    let filtrados = vehiculos;
    if (filtro === "economica") filtrados = vehiculos.filter(v => v.Precio < 50);
    else if (filtro === "suv") filtrados = vehiculos.filter(v => v.Tipo === "SUV" || v.Tipo === "Pickup");
    else if (filtro === "lujo") filtrados = vehiculos.filter(v => v.Precio >= 100);
    else if (filtro === "sedan") filtrados = vehiculos.filter(v => v.Tipo === "Sedán" || v.Tipo === "Sedán Deportivo");
    else if (filtro === "capacidad5") filtrados = vehiculos.filter(v => v.CapacidadPasajeros >= 5);
    else if (filtro === "recientes") filtrados = vehiculos.filter(v => v.Año >= new Date().getFullYear() - 2);
    return filtrados;
  };

  const handleFiltro = (categoria) => {
    setFiltro(categoria);
  };

  if (loading) return <div style={{ padding: 24, textAlign: "center" }}>Cargando...</div>;
  if (error) return <div style={{ padding: 24, textAlign: "center", color: "#b91c1c" }}>{error}</div>;

  return (
    <section className="seccion-carros" id="autos">
      <div className="contenedor">
        <div className="seccion-head">
          <h2 style={{ fontSize: "2rem", color: "var(--brand)" }}>Elige el coche que se ajuste a ti</h2>
          <div className="filtro" style={{ display: "flex", gap: "10px", flexWrap: "wrap" }}>
            <button className={`chip small ${filtro === "todos" ? "activo" : ""}`} onClick={() => handleFiltro("todos")}>
              Todos
            </button>
            <button className={`chip small ${filtro === "economica" ? "activo" : ""}`} onClick={() => handleFiltro("economica")}>
              Económico
            </button>
            <button className={`chip small ${filtro === "suv" ? "activo" : ""}`} onClick={() => handleFiltro("suv")}>
              SUV
            </button>
            <button className={`chip small ${filtro === "lujo" ? "activo" : ""}`} onClick={() => handleFiltro("lujo")}>
              Lujo
            </button>
            <button className={`chip small ${filtro === "sedan" ? "activo" : ""}`} onClick={() => handleFiltro("sedan")}>
              Sedán
            </button>
            <button className={`chip small ${filtro === "capacidad5" ? "activo" : ""}`} onClick={() => handleFiltro("capacidad5")}>
              5+ Pasajeros
            </button>
            <button className={`chip small ${filtro === "recientes" ? "activo" : ""}`} onClick={() => handleFiltro("recientes")}>
              Recientes
            </button>
          </div>
        </div>
        <div className="tarjeta-grid" style={{
          display: "grid",
          overflowY: "auto",
          gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))",
          gap: "20px",
          paddingBottom: "20px",
          scrollSnapType: "x mandatory",
        }}>
          {filtrarVehiculos().length ? (
            filtrarVehiculos().map((carro) => (
              <div style={{ flex: "0 0 300px", scrollSnapAlign: "start" }} key={carro.ID_Vehiculo}>
                <TarjetaReserva
                  key={carro.ID_Vehiculo}
                  carro={{
                    ID_Vehiculo: carro.ID_Vehiculo,
                    imagen: carro.ImagenUrl ? `http://127.0.0.1:5000${carro.ImagenUrl}` : "./assets/lambo.jpg",
                    nombre: `${carro.Marca} ${carro.Modelo}`,
                    tipo: carro.Tipo,
                    precio: carro.Precio,
                    combustible: carro.TipoCombustible || carro.Tipo,
                    asientos: carro.CapacidadPasajeros,
                    año: carro.Año,
                  }}
                  onSelect={(vehiculo) => onSelectVehicle(vehiculo || carro)} // Asegura que pase el objeto completo
                />
              </div>
            ))
          ) : null}
        </div>
      </div>
    </section>
  );
}