import React from "react";
import { useNavigate } from "react-router-dom";
import "../styles.css";

export default function Navbar({ usuario, setUsuario }) {
  const navigate = useNavigate();

  function handleLogout() {
    setUsuario(null);
    localStorage.removeItem('usuario');
    navigate('/');
  }

  return (
    <nav className="navbar">
      <div className="nav-unido">
        <div className="marca">
          <div className="logo">RC</div>
          <span className="nombre-marca">Renta Car</span>
        </div>
        <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
          {usuario ? (
            <div className="dropdown" style={{ position: 'relative' }}>
              <button className="btn btn-primario" style={{ padding: '8px 16px', borderRadius: '4px' }}>
                {usuario?.Nombre ? usuario.Nombre : 'Perfil'}
              </button>
              <div className="dropdown-content" style={{ position: 'absolute', background: '#fff', boxShadow: '0 4px 8px rgba(0,0,0,0.1)', borderRadius: '4px', padding: '10px', zIndex: 1 }}>
                <p style={{ margin: '0 0 5px' }}>Bienvenido, {usuario?.Nombre} {usuario?.Apellido}</p>
                <p>Cédula: {usuario?.Cedula}</p>
                <p>Teléfono: {usuario?.Telefono}</p>
                <p>Correo: {usuario?.Correo_Electronico}</p>
                <p>Licencia: {usuario?.Licencia_Conducir}</p>
                {usuario.esAdmin && <a href="/admin" style={{ display: 'block', marginBottom: '5px' }}>Dashboard Admin</a>}
                <button onClick={handleLogout} style={{ width: '100%', padding: '8px', background: '#b91c1c', color: '#fff', border: 'none', borderRadius: '4px' }}>Cerrar Sesión</button>
              </div>
            </div>
          ) : (
            <>
              <button className="btn btn-contorno" onClick={() => navigate('/login')} style={{ padding: '8px 16px', borderRadius: '4px' }}>Iniciar Sesión</button>
              <button className="btn btn-primario" onClick={() => navigate('/register')} style={{ padding: '8px 16px', borderRadius: '4px' }}>Registrarse</button>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}